import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { useOnboarding } from "@/hooks/useOnboarding";
import { useUser, UserState } from "@/hooks/useUser";
import { useTask } from "@/hooks/useTask";
import { useLockFn } from "@/hooks/useLockFn";
import { TaskId } from "@/types/task";
import { uploadUserInfo, editProfile } from "@/http/api";
import { Gender } from "@sitin/api-proto/gen/archat_api/user_api";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";
import { toast } from "@/utils/toast";
import { getSavedInviteCode } from "@/utils/referral";
import Lottie from "lottie-react";
import icBundleColorCash from "@/assets/images/ic_bundle_color_cash.webp";
import Username from "./Username";
import Age from "./Age";
import Photo from "./Photo";
import Phone from "./Phone";

const TOTAL_PAGES = 4;

const PAGE_REWARDS: Record<number, number> = {
  1: 0.1, // username
  2: 0.1, // age
  3: 0.3, // photo
};

export default function OnboardingContainer() {
  const navigate = useNavigate();
  const [showBubbleTip, setShowBubbleTip] = useState(false);
  const [showMoneyAnimation, setShowMoneyAnimation] = useState(false);
  const [onboardingMoneyAnimation, setOnboardingMoneyAnimation] = useState<Record<string, unknown> | null>(null);

  const {
    currentPage,
    setCurrentPage,
    latestPage,
    setLatestPage,
    inputUserName,
    inputAge,
    fakeCash,
    setFakeCash,
    reset: resetOnboarding,
  } = useOnboarding();

  // 根据当前页码派生期望金额，避免累加状态丢失导致显示为 0
  const expectedCash = useMemo(() => {
    let cash = 0;
    for (let i = 1; i < currentPage; i++) {
      cash += PAGE_REWARDS[i] || 0;
    }
    return Math.round(cash * 10) / 10;
  }, [currentPage]);

  // 动画期间显示 fakeCash（含刚领取的奖励），否则显示派生值
  const displayCash = showMoneyAnimation ? fakeCash : expectedCash;

  const { isReady, userState, setUserInfo } = useUser();
  const { finishTask } = useTask();

  useEffect(() => {
    if (!isReady) return;

    if (userState === UserState.NotLogin) {
      navigate("/onboarding", { replace: true });
      return;
    }

    if (userState === UserState.FullRegister) {
      navigate("/", { replace: true });
      return;
    }
  }, [isReady, userState, navigate]);

  // 拦截系统返回键，防止返回到登录页
  useEffect(() => {
    // 推入一条 history 记录，让系统返回键触发 popstate 而非离开页面
    window.history.pushState({ onboarding: true }, "");

    const onPopState = () => {
      if (currentPage > 1) {
        setCurrentPage(currentPage - 1);
      }
      // 无论在哪页，都重新 push 一条记录，防止下次返回离开页面
      window.history.pushState({ onboarding: true }, "");
    };

    window.addEventListener("popstate", onPopState);
    return () => window.removeEventListener("popstate", onPopState);
  }, [currentPage, setCurrentPage]);

  useEffect(() => {
    if (currentPage === 1) {
      setShowBubbleTip(true);
      const timer = setTimeout(() => {
        setShowBubbleTip(false);
      }, 5000);
      return () => clearTimeout(timer);
    } else {
      setShowBubbleTip(false);
    }
  }, [currentPage]);

  useEffect(() => {
    fetch("/animations/onboarding_money.json")
      .then((res) => res.json())
      .then((data) => setOnboardingMoneyAnimation(data))
      .catch((err) => console.error("Failed to load animation:", err));
  }, []);

  const handleContinue = async () => {
    // 防止动画播放期间重复点击
    if (showMoneyAnimation) return;

    if (currentPage < TOTAL_PAGES) {
      const increaseAmount = PAGE_REWARDS[currentPage] || 0;

      if (increaseAmount > 0) {
        setFakeCash(expectedCash + increaseAmount);
        // 播放钱币动画
        setShowMoneyAnimation(true);
        setTimeout(() => {
          setShowMoneyAnimation(false);
          gotoNextPage();
        }, 2000);
      } else {
        gotoNextPage();
      }
    } else {
      await handleUploadUserInfo();
    }
  };

  const gotoNextPage = () => {
    const newPage = currentPage + 1;
    if (newPage > latestPage) {
      setLatestPage(newPage);
    }
    setCurrentPage(newPage);
  };

  const handleBack = () => {
    if (currentPage > 1) {
      setCurrentPage(currentPage - 1);
    } else {
      resetOnboarding();
      navigate("/onboarding", { replace: true });
    }
  };

  const handleUploadUserInfo = useLockFn(async () => {
    try {
      const referralCode = getSavedInviteCode();
      const response = await uploadUserInfo({
        username: inputUserName,
        age: inputAge,
        gender: Gender.FEMALE,
        referralCode,
      });

      if (response.userInfo) {
        const latestPhoneNumber = useOnboarding.getState().inputPhoneNumber;
        await editProfile({ phoneNumber: `+1 ${latestPhoneNumber}` });
        setUserInfo(response.userInfo);

        // 埋点：Onboarding 完成
        bpTrack(EventName.pwa_onboarding_success);

        // 完成注册任务
        await finishTask(TaskId.Register);
        navigate("/", { replace: true });
      } else {
        toast.error("Failed to upload user info. Please try again.");
      }
    } catch (error) {
      console.error("Upload user info failed:", error);
      toast.error("An error occurred. Please try again.");
    }
  });

  return (
    <div className="flex flex-col h-full overflow-hidden bg-surface">
      <div className="flex items-center justify-between h-[50px] px-6 mt-[var(--sat,0px)]">
        <button
          onClick={handleBack}
          aria-label="Go back"
          className="flex items-center justify-center w-11 h-11 -ml-2 border-none bg-transparent"
        >
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
        </button>

        {currentPage <= 3 && (
          <div className="relative flex flex-col items-end">
            <div className="relative flex items-center justify-center h-[30px] py-2.5 px-3 gap-[3px] rounded-[99999px] bg-[#f7f2ec]">
              <img src={icBundleColorCash} alt="coin" className="w-[22px] h-[22px]" />
              <span className="text-[#05ae18] font-semibold text-[15px] leading-normal tracking-[-0.3px] text-center">
                $ {displayCash.toFixed(1)}
              </span>

              {/* 钱币动画 */}
              {showMoneyAnimation && onboardingMoneyAnimation && (
                <div className="absolute -top-5 left-1/2 -translate-x-1/2 pointer-events-none z-10">
                  <Lottie
                    animationData={onboardingMoneyAnimation}
                    autoplay={true}
                    loop={false}
                    style={{ width: 80, height: 80 }}
                  />
                </div>
              )}
            </div>

            {/* 气泡提示 */}
            {showBubbleTip && currentPage === 1 && (
              <div className="absolute top-[40px] right-0 flex flex-col items-end z-20 animate-in fade-in slide-in-from-top-1 duration-300">
                <div className="w-0 h-0 mr-[26px] mb-[-1px] border-l-[6px] border-l-transparent border-r-[6px] border-r-transparent border-b-[6px] border-b-[#05ae18]" />
                <div className="py-[8px] px-[12px] rounded-[8px] bg-[#05ae18] shadow-[0px_2px_8px_rgba(0,0,0,0.15)] text-white font-normal text-[13px] leading-[18px] whitespace-nowrap">
                  Signup to Unlock Cashouts
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      <div className="flex-1 flex flex-col w-full h-full p-6">
        {currentPage === 1 && <Username onContinue={handleContinue} />}
        {currentPage === 2 && <Age onContinue={handleContinue} />}
        {currentPage === 3 && <Photo onContinue={handleContinue} />}
        {currentPage === 4 && <Phone onContinue={handleUploadUserInfo} />}
      </div>
    </div>
  );
}
